import{_ as e,o,c as t,a3 as l}from"./chunks/framework.BTFg6ESq.js";const m=JSON.parse('{"title":"消息数据编辑器 (高级)","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/messages/message-data-editor.md","filePath":"user-guide/tools/llm-chat/messages/message-data-editor.md","lastUpdated":1778239080000}'),s={name:"user-guide/tools/llm-chat/messages/message-data-editor.md"};function i(r,a,d,c,n,h){return o(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="消息数据编辑器-高级" tabindex="-1">消息数据编辑器 (高级) <a class="header-anchor" href="#消息数据编辑器-高级" aria-label="Permalink to &quot;消息数据编辑器 (高级)&quot;">​</a></h1><p>消息数据编辑器是一个面向高级用户的调试工具，允许你直接查看并修改消息在数据库中的原始 JSON 结构。</p><h2 id="_1-进入编辑器" tabindex="-1">1. 进入编辑器 <a class="header-anchor" href="#_1-进入编辑器" aria-label="Permalink to &quot;1. 进入编辑器&quot;">​</a></h2><ol><li>将鼠标悬停在消息上。</li><li>点击更多菜单 (<code>···</code>)。</li><li>选择 <strong>🗄️ 数据编辑 (高级)</strong>。</li></ol><h2 id="_2-核心编辑区域" tabindex="-1">2. 核心编辑区域 <a class="header-anchor" href="#_2-核心编辑区域" aria-label="Permalink to &quot;2. 核心编辑区域&quot;">​</a></h2><p>编辑器提供了一个全功能的代码编辑器（基于 CodeMirror 或 Monaco），加载了该消息的原始数据：</p><ul><li><strong>Role (角色)</strong>: <code>system</code>, <code>user</code>, <code>assistant</code>, <code>tool</code> 等。</li><li><strong>Content (内容)</strong>: 消息的文本原文。</li><li><strong>Metadata (元数据)</strong>: <ul><li><code>tokens</code>: 预估的 Token 数。</li><li><code>model</code>: 生成该消息的模型 ID。</li><li><code>sessionVariableSnapshot</code>: 该时刻的<a href="./../macro-system/session-variables">会话变量</a>快照。</li><li><code>toolCalls</code>: 如果是工具调用消息，包含具体的函数名和参数。</li><li><code>attachments</code>: 关联的附件列表。</li></ul></li></ul><h2 id="_3-使用场景" tabindex="-1">3. 使用场景 <a class="header-anchor" href="#_3-使用场景" aria-label="Permalink to &quot;3. 使用场景&quot;">​</a></h2><h3 id="_3-1-修复损坏的数据" tabindex="-1">3.1 修复损坏的数据 <a class="header-anchor" href="#_3-1-修复损坏的数据" aria-label="Permalink to &quot;3.1 修复损坏的数据&quot;">​</a></h3><p>如果你在导入第三方角色卡或会话时发现某些消息渲染异常，可以通过数据编辑器手动修正元数据或角色定义。</p><h3 id="_3-2-模拟特定的上下文状态" tabindex="-1">3.2 模拟特定的上下文状态 <a class="header-anchor" href="#_3-2-模拟特定的上下文状态" aria-label="Permalink to &quot;3.2 模拟特定的上下文状态&quot;">​</a></h3><p>通过手动修改 <code>sessionVariableSnapshot</code>，你可以强制改变会话变量的值，从而测试 Agent 在不同变量状态下的反应，而无需重新进行多轮对话。</p><h3 id="_3-3-深度调试工具调用" tabindex="-1">3.3 深度调试工具调用 <a class="header-anchor" href="#_3-3-深度调试工具调用" aria-label="Permalink to &quot;3.3 深度调试工具调用&quot;">​</a></h3><p>你可以直接查看 <code>toolCalls</code> 的原始参数和 <code>tool</code> 角色的原始返回结果，这对于排查工具调用逻辑错误非常有用。</p><h2 id="_4-注意事项" tabindex="-1">4. 注意事项 <a class="header-anchor" href="#_4-注意事项" aria-label="Permalink to &quot;4. 注意事项&quot;">​</a></h2><div class="warning custom-block github-alert"><p class="custom-block-title">**数据风险**</p><p>直接编辑原始数据具有一定风险。不合法的 JSON 格式或错误的字段定义可能导致消息无法渲染或应用崩溃。在保存修改前，请务必确认数据的完整性。</p></div><hr><h3 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h3><ul><li><a href="./../macro-system/session-variables">会话变量系统</a></li><li><a href="./../tool-calling/execution-debug">工具调用调试</a></li><li><a href="./../context-pipeline/analyzer">上下文分析器</a></li></ul>',19)])])}const _=e(s,[["render",i]]);export{m as __pageData,_ as default};
